```javascript
// Node 18+ recomendado
import fs from 'fs';
import fetch from 'node-fetch';

async function githubApi(path, body = null, method = 'GET') {
  const base = 'https://api.github.com';
  const resp = await fetch(base + path, {
    method,
    headers: {
      Authorization: `Bearer ${process.env.GITHUB_TOKEN}`,
      'User-Agent': 'release-notes-bot',
      Accept: 'application/vnd.github.v3+json'
    },
    body: body ? JSON.stringify(body) : undefined
  });
  return resp.json();
}

async function collectMergedPRs(owner, repo) {
  const pulls = await githubApi(`/repos/${owner}/${repo}/pulls?state=closed&per_page=100`);
  return pulls
    .filter(p => p.merged_at && p.base && p.base.ref === 'main')
    .map(p => ({ number: p.number, title: p.title, body: p.body || '', user: p.user?.login, labels: p.labels?.map(l => l.name) }));
}

function buildPrompt(prs, repo) {
  const lines = prs.map(p => `- PR #${p.number} ${p.title} (by ${p.user})\n  labels: ${p.labels?.join(', ') || 'none'}\n  ${p.body.split('\n').slice(0,4).join(' ')}\n`);
  return `Eres un redactor de notas de versión. Resume los siguientes PRs mergeados en una sección de notas de versión en markdown para ${repo}. Devuelve secciones: Highlights, Features, Fixes, Breaking changes si aplica.\n\n${lines.join('\n')}`;
}

async function callOpenAI(prompt) {
  const url = 'https://api.openai.com/v1/chat/completions';
  const resp = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${process.env.OPENAI_API_KEY}`
    },
    body: JSON.stringify({
      model: 'gpt-4',
      messages: [
        { role: 'system', content: 'Resume changelogs de forma concisa y estructurada.' },
        { role: 'user', content: prompt }
      ],
      max_tokens: 600,
      temperature: 0.2
    })
  });
  const data = await resp.json();
  return data.choices?.[0]?.message?.content || '';
}

async function createRelease(owner, repo, tagName, body) {
  const payload = { tag_name: tagName, name: tagName, body, draft: false, prerelease: false };
  return githubApi(`/repos/${owner}/${repo}/releases`, payload, 'POST');
}

async function main() {
  const repoFull = process.env.GITHUB_REPOSITORY;
  const [owner, repo] = repoFull.split('/');
  const tagRef = process.env.GITHUB_REF;
  const tag = tagRef.split('/').pop();

  const prs = await collectMergedPRs(owner, repo);
  if (!prs.length) {
    console.log('No se encontraron PRs mergeados. Saliendo.');
    return;
  }

  const prompt = buildPrompt(prs, repo);
  const notes = await callOpenAI(prompt);

  const release = await createRelease(owner, repo, tag, notes);
  console.log('Release creado:', release.html_url || release.id);
}

main().catch(err => { console.error(err); process.exit(1); });
```

Buenas prácticas:
- Restringe permisos de tokens y valida scopes.
- Mantén temperature baja para salidas más deterministas.
- Sanitiza cuerpos de PR para evitar revelar secretos.

## 6. Casos de uso (con emojis)

- 📦 Publicación automática: publicar notas al empujar una etiqueta.
- 📝 Borradores de PR: abrir un PR con cambios de CHANGELOG para revisión.
- 🔍 Resúmenes para QA: listado breve de áreas cambiadas para testers.
- 📣 Resúmenes para producto o soporte.
- 🔗 Enriquecimiento de changelog: clasificar PRs por tipo automáticamente.

## 7. Comparación

| Enfoque | Características | Precio | Mejor para |
|---|---:|---|---|
| Generador AI | Resúmenes en lenguaje natural, prompts personalizables | Depende del proveedor de LLM (facturación por uso) | Equipos que quieren notas legibles y contextuales
| Release Drafter | Drafts basados en plantillas y etiquetas | Gratis (open source) | Equipos que prefieren plantillas deterministas
| Notas manuales | Control humano total | Coste de tiempo | Proyectos pequeños o con requisitos legales estrictos

Nota: consulta la documentación de tu proveedor de LLM para precios actuales; aquí no se listan tarifas específicas.

## 8. Pros y Contras

Pros:
- Ahorra tiempo y mantiene consistencia de estilo.
- Escalable a múltiples repositorios.

Contras:
- Coste por uso del LLM.
- Riesgo de invención de detalles (hallucinations) si no se controlan prompts.
- Consideraciones de privacidad y cumplimiento al enviar datos a servicios externos.

## 9. Errores comunes / Trampas

- Enviar datos sensibles sin filtrar al LLM.
- Publicar automáticamente sin revisión humana.
- Prompts demasiado abiertos que llevan a respuestas inventadas.
- No gestionar reintentos o límites de velocidad en llamadas a la API.

## 10. Conclusión

Construir un generador AI de notas de versión con GitHub Actions facilita la creación de notas legibles sin cambiar el flujo de trabajo de los desarrolladores. Empieza con un prototipo que genere borradores (draft releases o PRs), valida los resultados y después automatiza por completo si la calidad es satisfactoria. Recomendación: instrumenta el pipeline con validaciones, usa respuestas estructuradas del modelo y mantén control humano para versiones públicas.

